#include <vector>

#include "gtest/gtest.h"
#include "test/cpp/benchmarks/benchmarkUtils.h"
#include "test/cpp/taskSystem/gemmTest/staticGemmKernel.h"
#include "test/cpp/taskSystem/gemmTest/taskSystemGemmKernel.h"

namespace {
// PK: Code generated by gpt5-mini, with my minor changes.

static float run_gpu_benchmark_static(const float* dA, const float* dB,
                                      float* dC, int M, int N, int K,
                                      int repetitions, int warmup) {
  return test::bench::Benchmark(repetitions, warmup, staticGemm, dA, dB, dC, M,
                                N, K);
}

static float run_gpu_benchmark_tasksystem(const float* dA, const float* dB,
                                          float* dC, int M, int N, int K,
                                          int repetitions, int warmup) {
  void* state = nullptr;
  HIP_CHECK(initTaskSystemGemm(&state));
  float res = test::bench::Benchmark(repetitions, warmup, taskSystemGemm, state,
                                     dA, dB, dC, M, N, K);
  HIP_CHECK(deinitTaskSystemGemm(state));
  return res;
}

TEST(GemmBenchmark, StaticVsTaskSystem) {
  const int M = 2048;
  const int N = 1536;
  const int K = 2048;
  const int repetitions = 100;  // adjust as needed for stable timings
  const int warmup = 10;        // adjust as needed for stable timings

  const size_t sizeA = size_t(M) * size_t(K);
  const size_t sizeB = size_t(K) * size_t(N);
  const size_t sizeC = size_t(M) * size_t(N);

  // Host buffers
  std::vector<float> hA(sizeA, 1.0f);
  std::vector<float> hB(sizeB, 1.0f);
  std::vector<float> hC(sizeC, 0.0f);

  // Device buffers
  float *dA = nullptr, *dB = nullptr, *dC = nullptr;
  HIP_CHECK(hipMalloc(&dA, sizeA * sizeof(float)));
  HIP_CHECK(hipMalloc(&dB, sizeB * sizeof(float)));
  HIP_CHECK(hipMalloc(&dC, sizeC * sizeof(float)));

  HIP_CHECK(
      hipMemcpy(dA, hA.data(), sizeA * sizeof(float), hipMemcpyHostToDevice));
  HIP_CHECK(
      hipMemcpy(dB, hB.data(), sizeB * sizeof(float), hipMemcpyHostToDevice));

  // Benchmark static GEMM
  HIP_CHECK(hipMemset(dC, 0, sizeC * sizeof(float)));
  float avg_static_ms =
      run_gpu_benchmark_static(dA, dB, dC, M, N, K, repetitions, warmup);
  HIP_CHECK(
      hipMemcpy(hC.data(), dC, sizeC * sizeof(float), hipMemcpyDeviceToHost));

  // Validate correctness for staticGemm
  bool ok_static = true;
  const float expect = float(K);
  for (size_t i = 0; i < sizeC; ++i) {
    if (std::fabs(hC[i] - expect) > 1e-2f) {
      ok_static = false;
      break;
    }
  }

  // Benchmark taskSystem GEMM
  HIP_CHECK(hipMemset(dC, 0, sizeC * sizeof(float)));
  float avg_task_ms =
      run_gpu_benchmark_tasksystem(dA, dB, dC, M, N, K, repetitions, warmup);
  HIP_CHECK(
      hipMemcpy(hC.data(), dC, sizeC * sizeof(float), hipMemcpyDeviceToHost));

  // Validate correctness for taskSystemGemm
  bool ok_task = true;
  for (size_t i = 0; i < sizeC; ++i) {
    if (std::fabs(hC[i] - expect) > 1e-2f) {
      ok_task = false;
      break;
    }
  }

  // Free device memory
  HIP_CHECK(hipFree(dA));
  HIP_CHECK(hipFree(dB));
  HIP_CHECK(hipFree(dC));

  // Print benchmark res
  // Print benchmark results
  std::cout << "[GEMM BENCHMARK] M=" << M << " N=" << N << " K=" << K
            << " reps=" << repetitions << std::endl;
  std::cout << "  staticGemm avg kernel time (ms): " << avg_static_ms
            << "  valid=" << (ok_static ? "YES" : "NO") << std::endl;
  std::cout << "  taskSystemGemm avg kernel time (ms): " << avg_task_ms
            << "  valid=" << (ok_task ? "YES" : "NO") << std::endl;
  std::cout << "Task system overhead is "
            << ((avg_task_ms / avg_static_ms) * 100) - 100 << "%." << std::endl;

  // This test is primarily a benchmark; still assert correctness
  ASSERT_TRUE(ok_static) << "staticGemm produced incorrect results";
  ASSERT_TRUE(ok_task) << "taskSystemGemm produced incorrect results";
}
}  // namespace